#include <bits/stdc++.h>
using namespace std;
const int N=1005;
int n,m,a[N][N],mn[N][N][2],mx[N][N][2];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		string s;
		cin>>s;
		for(int j=0;j<m;j++)
		{
			if(s[j]=='#') a[i][j+1]=0;
			else a[i][j+1]=1; 
		}
	}
	if(a[1][1]==0)
	{
		cout<<-1;
		return 0;
	}
	memset(mn,0x3f,sizeof(mn));
	mn[1][1][0]=mn[1][1][1]=0;
	memset(mx,128,sizeof(mx));
	mx[1][1][0]=mx[1][1][1]=0;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			if(a[i][j]==0) continue;
			mn[i][j][0]=min(mn[i][j][0],min(mn[i][j-1][0],mn[i-1][j][1]+1));
			mn[i][j][1]=min(mn[i][j][1],min(mn[i-1][j][1],mn[i][j-1][0]+1));
			mx[i][j][0]=max(mx[i][j][0],max(mx[i][j-1][0],mx[i-1][j][1]+1));
			mx[i][j][1]=max(mx[i][j][1],max(mx[i-1][j][1],mx[i][j-1][0]+1));
		}
	}
	if(min(mn[n][m][0],mn[n][m][1])==0x3f3f3f3f) cout<<-1;
	else cout<<max(mx[n-1][m][1],mx[n][m-1][0])<<" "<<min(mn[n][m-1][0],mn[n-1][m][1]);
	return 0;
}
